SELECT id, user_id, username, phone, email, avatar_url, role, bio, status, ctime, mtime, deleted
FROM user


        AND (username LIKE CONCAT('%', #{keyword}, '%')
        OR email LIKE CONCAT('%', #{keyword}, '%')
        OR phone LIKE CONCAT('%', #{keyword}, '%'))


        AND role = #{role}


        AND status = #{status}


        AND deleted = #{deleted}


ORDER BY ctime DESC
